// Fast O(1) queue implementation
export default class FastQueue {
    constructor() {
        this.head = 0;
        this.tail = 0;
        this.items = [];
        this.size = 0;
    }
    enqueue(item) {
        this.items[this.tail] = item;
        this.tail = (this.tail + 1) % this.getCapacity();
        this.size++;
        // Resize if needed
        if (this.size === this.getCapacity()) {
            this.resize();
        }
    }
    dequeue() {
        if (this.isEmpty()) {
            return undefined;
        }
        const item = this.items[this.head];
        this.items[this.head] = undefined; // Clear reference
        this.head = (this.head + 1) % this.getCapacity();
        this.size--;
        return item;
    }
    peek() {
        if (this.isEmpty()) {
            return undefined;
        }
        return this.items[this.head];
    }
    isEmpty() {
        return this.size === 0;
    }
    getLength() {
        return this.size;
    }
    getCapacity() {
        return this.items.length;
    }
    resize() {
        const newCapacity = Math.max(1, this.getCapacity() * 2);
        const newItems = new Array(newCapacity);
        for (let i = 0; i < this.size; i++) {
            newItems[i] = this.items[(this.head + i) % this.getCapacity()];
        }
        this.items = newItems;
        this.head = 0;
        this.tail = this.size;
    }
}
